function hashText(value) {
  let hash = 2166136261;
  const text = String(value || '');
  for (let index = 0; index < text.length; index += 1) {
    hash ^= text.charCodeAt(index);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

function pick(items, seed, salt) {
  return items[hashText([seed, salt].join('|')) % items.length];
}

function rows(values) {
  return values.map((value, index) => {
    const [name, reason, caution = ''] = value.split('|');
    return { rank: index + 1, name, reason, caution };
  });
}

function makePack(entry) {
  return {
    content_lane: entry.lane,
    format_angle: entry.angle,
    theme: entry.theme,
    hook_title: entry.title,
    subtitle: entry.subtitle,
    visual_mood_hint: entry.visual,
