const sunoData =
  data.response?.sunoData ||
  data.sunoData ||
  data.response?.data ||
  data.data ||
  [];

function asList(value) {
  if (Array.isArray(value)) return value;
  if (value && typeof value === 'object') return [value];
  return [];
}

function audioUrlFor(item) {
  return item?.audioUrl ||
    item?.streamAudioUrl ||
    item?.sourceAudioUrl ||
    item?.sourceStreamAudioUrl ||
    item?.audio_url ||
    item?.stream_audio_url ||
    item?.url ||
    null;
}

function durationFor(item) {
  const duration = Number(item?.duration || item?.audioDuration || item?.durationSeconds || item?.metadata?.duration || 0);
  return Number.isFinite(duration) ? duration : 0;
}

function fallbackBgm(message) {
  const fallbackUrl =
    previous.config?.fallback_bgm_audio_url ||
    previous.fallback_bgm_audio_url ||
    'C:/dev/n8n-youtube-shorts-automation/assets/fallback-bgm.mp3';
  return [{
    json: {
      ...previous,
      bgm_poll_response: response,
      bgm_state: status || 'FALLBACK',
      bgm_failed: true,
      bgm_fallback_used: true,
      bgm_failure_message: message,
      bgm_audio_url: fallbackUrl,
      bgm_audio_duration: null,
      bgm_audio_choice: null,
      bgm_retry_attempted: true,
    },
  }];
}

const candidates = asList(sunoData).filter((item) => audioUrlFor(item));
const best = [...candidates].sort((left, right) => durationFor(right) - durationFor(left))[0] || null;
const fallbackUrl =
  data.response?.audioUrl ||
  data.response?.streamAudioUrl ||
  data.audioUrl ||
  data.streamAudioUrl ||
  null;
const bgmUrl = best ? audioUrlFor(best) : fallbackUrl;
const failed = ['CREATE_TASK_FAILED', 'GENERATE_AUDIO_FAILED', 'CALLBACK_EXCEPTION', 'SENSITIVE_WORD_ERROR', 'FAIL', 'FAILED', 'ERROR'].includes(status);
if (failed) {
  return fallbackBgm('KIE BGM failed. state=' + status + ', taskId=' + (previous.bgm_task_id || '-') + ', message=' + (data.failMsg || data.message || response.msg || response.error || ''));
}
if (!bgmUrl) {
  return fallbackBgm('KIE BGM still not ready after retry. state=' + (status || '-') + ', taskId=' + (previous.bgm_task_id || '-'));
}
return [{ json: { ...previous, bgm_poll_response: response, bgm_state: status, bgm_failed: false, bgm_audio_url: bgmUrl, bgm_audio_duration: best ? durationFor(best) : null, bgm_audio_choice: best, bgm_retry_attempted: true } }];

